mapper.select:
SELECT e.expensesID, e.accrualDate, e.cost, e.tantouName, e.settlementType, e.settlementDate, e.expensesType, e.happenAddress, e.deleteFlg, e.receiptPath, e.m_expenses_id as mexpensesId, e.insertDate, e.updateDate, m.expensesTypeName, m.expenseName as expenseNameText FROM ems.expenses e LEFT JOIN ems.m_expenses m ON e.m_expenses_id = m.id WHERE e.deleteFlg = '0'
AND e.accrualDate >= #{fromDate}
AND e.accrualDate <= #{toDate}
AND e.tantouName = #{tantouName}
AND e.expensesType = #{expensesType}
AND e.settlementDate IS NOT NULL
AND e.settlementDate IS NULL
ORDER BY e.accrualDate ASC

mapper.update:
UPDATE ems.expenses
SET deleteFlg = '1'
WHERE expensesID = #{expensesID}
